// In server.js, the main hub where Node.js resides
const express = require('express');
const mongoose = require('mongoose');
const app = express();

mongoose.connect('mongodb://localhost:27017/rooms', { useNewUrlParser: true, useUnifiedTopology: true });

app.use(express.json());

// Room Schema and Model, defining our room's form
const roomSchema = new mongoose.Schema({
  name: String,
  capacity: Number
});
const Room = mongoose.model('Room', roomSchema);

// API to add a room, a door to the new chamber
app.post('/api/rooms', (req, res) => {
  const newRoom = new Room(req.body);
  newRoom.save()
    .then(room => res.status(201).send(room))
    .catch(err => res.status(400).send(err));
});

// To list all rooms, a scroll through the halls
app.get('/api/rooms', (req, res) => {
  Room.find()
    .then(rooms => res.send(rooms))
    .catch(err => res.status(404).send({ message: "No rooms found!" }));
});

// The frontend, React awaits, with Redux for state
import React from 'react';
import { connect } from 'react-redux';
import { fetchRooms } from './actions';

class Rooms extends React.Component {
  componentDidMount() {
    this.props.fetchRooms();
  }

  render() {
    return (
      <div>
        {this.props.rooms.map(room =>
          <div key={room._id}>
            {room.name} has {room.capacity} seats.
          </div>
        )}
      </div>
    );
  }
}

const mapStateToProps = state => ({
  rooms: state.rooms
});

export default connect(mapStateToProps, { fetchRooms })(Rooms);
