We must first embrace the art of recursion, a task,
That though complex, when done with care and craft,
Will yield the derivative of any function we part.

```cpp
#include <iostream>
#include <string>
#include <map>
#include <cassert>

using namespace std;

// A map to hold constants and their derivatives
map<string, string> constants = {
    {"x", "1"}, // Derivative of x is 1
    {"e", "0"}  // Derivative of e (base of natural log) is 0
};

// Function to parse and differentiate
string diff(string expr) {
    if (expr.empty()) return expr;

    // Check for constants and their derivatives
    auto it = constants.find(expr);
    if (it != constants.end()) return it->second;

    // Differentiate variables
    if (expr == "x") return "1";

    // Handle multiplication
    size_t pos = expr.find('*');
    if (pos != string::npos) {
        return diff(expr.substr(0, pos)) + "*" + diff(expr.substr(pos + 1));
    }

    // Handle addition and subtraction
    pos = expr.find('+');
    if (pos != string::npos) {
        return diff(expr.substr(0, pos)) + "+" + diff(expr.substr(pos + 1));
    }
    pos = expr.find('-');
    if (pos != string::npos) {
        return diff(expr.substr(0, pos)) + "-" + diff(expr.substr(pos + 1));
    }

    // Handle exponentiation
    pos = expr.find('^');
    if (pos != string::npos) {
        string base = expr.substr(0, pos);
        string exp = expr.substr(pos + 1);
        return exp + "*" + base + "^" + to_string(stoi(exp) - 1);
    }

    // Default case: return the expression itself
    return expr;
}

int main() {
    string expr = "2*x^3 + 3*x^2 - 4*x + 5";
    cout << "Derivative of " << expr << " is " << diff(expr) << endl;
    assert(diff("2*x^3 + 3*x^2 - 4*x + 5") == "6*x^2 + 6*x - 4");
    return 0;
}
```
